const newEntry = userInput?.entries?.[0];
const submittedAt = userInput?.submittedAt;
const submissionMode = userInput?.submissionMode;
const token = userInput?.token;
const name = userInput?.name;
const productName = userInput?.entries?.[0].productName;

// Build reusable userInput snapshot
const userInputSnapshot = {
  token,
  submittedAt,
  submissionMode,
  name,
};

// If previous node is empty, treat as 200 (no existing bookings)
if (!previousNodeItems || previousNodeItems.length === 0) {
  return [
    {
      json: {
        status: 200,
        message: `You've successfully booked a Silver ad for ${productName || "your product"}`,
        userInput: userInputSnapshot,
        entry: newEntry,
      }
    }
  ];
}

// Count existing bookings per adType (case-insensitive)
const adTypeCounts = {
  platinum: 0,
  gold: 0,
  silver: 0,
};

for (const item of previousNodeItems) {
  const adType = item.json?.ad_type?.toLowerCase();
  if (adType && adTypeCounts.hasOwnProperty(adType)) {
    adTypeCounts[adType]++;
  }
}

// Extract full existing booking data
const existingBookings = previousNodeItems.map(item => item.json);

// Calculate total existing bookings across all adTypes
const totalBookings = adTypeCounts.platinum + adTypeCounts.gold + adTypeCounts.silver;

// Max 5 total bookings allowed across all adTypes combined
const MAX_BOOKINGS = 5;

if (totalBookings >= MAX_BOOKINGS) {
  return [
    {
      json: {
        status: 409,
        message: "Fully booked",
        userInput: userInputSnapshot,
        existingBookings,
        totalBookings,
        entry: newEntry,
      }
    }
  ];
}

// Under the limit — booking is successful
return [
  {
    json: {
      status: 200,
      message: `You've successfully booked a Silver ad for ${productName || "your product"}`,
      userInput: userInputSnapshot,
      existingBookings,
      totalBookings,
      entry: newEntry,
    }
  }
];

