const userInputItems = $('ALL: MERGE DATA').all();
const previousNodeItems = $input.all();

// ── helpers ──────────────────────────────────────────────────────────────────
const PREMIUM_TYPES = ['silver', 'gold', 'platinum'];
const MAX_PREMIUM   = 5;

function normalizeType(t = '') {
  return t.trim().toLowerCase();
}

function normalizeDate(dateStr = '') {
  const d = new Date(dateStr);
  return isNaN(d) ? dateStr : d.toISOString().split('T')[0]; // "2026-04-04"
}

// ── extract user input (first item) ──────────────────────────────────────────
const userItem      = userInputItems[0]?.json ?? {};
const entries       = Array.isArray(userItem.entries) ? userItem.entries : [];
const userInput = {
  token          : userItem.token          ?? null,
  submittedAt    : userItem.submittedAt    ?? null,
  submissionMode : userItem.submissionMode ?? null,
  name           : userItem.name           ?? null,
};

// ── count existing premium bookings PER DATE ──────────────────────────────────
const existingPremiumByDate = {};
const hasExistingBookings = previousNodeItems.length > 0 &&
  previousNodeItems.some(i => i.json && Object.keys(i.json).length > 0);

if (hasExistingBookings) {
  for (const item of previousNodeItems) {
    const adType = normalizeType(item.json?.ad_type ?? '');
    if (PREMIUM_TYPES.includes(adType)) {
      const date = normalizeDate(item.json?.date_scheduled ?? '');
      existingPremiumByDate[date] = (existingPremiumByDate[date] ?? 0) + 1;
    }
  }
}

// ── validate each submitted entry ────────────────────────────────────────────
const successEntries = [];
const failedEntries  = [];

// rolling counter per date, seeded from existing bookings
const rollingPremiumByDate = { ...existingPremiumByDate };

for (const entry of entries) {
  const adType    = normalizeType(entry.adType ?? '');
  const isPremium = PREMIUM_TYPES.includes(adType);

  if (isPremium) {
    const entryDate = normalizeDate(entry.date ?? '');
    const current   = rollingPremiumByDate[entryDate] ?? 0;

    if (current >= MAX_PREMIUM) {
      failedEntries.push({
        ...entry,
         reason: `The maximum of ${MAX_PREMIUM} premium ads (Silver, Gold, Platinum) has already been reached for ${new Date(entryDate).toLocaleDateString("en-US", {
      month: "long",
      day: "numeric",
      year: "numeric",
    })}.`,
      });
    } else {
      rollingPremiumByDate[entryDate] = current + 1;
      successEntries.push(entry);
    }
  } else {
    // Bronze — no limit
    successEntries.push(entry);
  }
}

// ── determine status code & message ──────────────────────────────────────────
let statusCode, message;

if (!hasExistingBookings && entries.length === 0) {
  // edge-case: nothing at all
  statusCode = 200;
  message    = 'You have successfully booked all entries.';
} else if (failedEntries.length === 0) {
  // all entries accepted
  statusCode = 200;
  message    = 'You have successfully booked all entries.';
} else if (successEntries.length === 0) {
  // every entry was rejected
  statusCode = 409;
  message    = 'Fully booked — no available premium ad slots remaining.';
} else {
  // mixed result
  statusCode = 207;
  message    = `Partial booking — ${successEntries.length} entry/entries accepted, ${failedEntries.length} rejected due to slot limits.`;
}

// ── build output ─────────────────────────────────────────────────────────────
return [
  {
    json: {
      status: statusCode,
      message,
      userInput,
      entries: {
        success : successEntries,
        failed  : failedEntries,
      },
      existingBookings: hasExistingBookings
        ? previousNodeItems.map(i => i.json)
        : [],
    },
  },
];

