const items = $input.all();

// HELPER: GET TODAY'S DATE STRING IN PHT (YYYY-MM-DD)
const nowUTC = new Date();
const nowPH = new Date(nowUTC.getTime() + 8 * 60 * 60 * 1000);
const todayPH = nowPH.toISOString().slice(0, 10); // e.g. "2026-05-14"

function isBronzeImageToday(entry) {
  return (
    entry.adType?.toLowerCase() === 'bronze' &&
    entry.socialPostType?.toLowerCase() === 'image' &&
    entry.date === todayPH
  );
}

for (const item of items) {
  const submittedAt = item.json.submittedAt;

  if (!submittedAt) {
    item.json.allowed = false;
    item.json.message = 'submittedAt field is missing';
    continue;
  }

  const date = new Date(submittedAt);
  const phHour = (date.getUTCHours() + 8) % 24;

  // TESTING PURPOSE: 4:00PM TO 6:00PM
  // const isRestrictedHour = phHour >= 16 && phHour < 18;

  // PROD: 8:00PM TO 12:00AM
  const isRestrictedHour = phHour >= 20 && phHour < 24;

  const submissionMode = item.json.submissionMode;
  const entries = item.json.entries || [];

  let hasBronzeImage = false;

  if (submissionMode === 'single') {
    const entry = entries[0];
    if (entry) {
      hasBronzeImage = isBronzeImageToday(entry);
    }
  } else if (submissionMode === 'multiple') {
    hasBronzeImage = entries.some(isBronzeImageToday);
  }

  if (hasBronzeImage && isRestrictedHour) {
    item.json.allowed = false;
    item.json.message = 'Submissions with Bronze ad type and Image post type between 8:00 PM and 12:00 AM PHT are not permitted.';
  } else {
    item.json.allowed = true;
  }
}

return items;

